<?php
$pageTitle='Marketing Campaigns';
require_once dirname(__DIR__,2) . '/includes/functions.php';
erpGuard('marketing_campaigns');
$pdo=getDB();$scope=operationalScope($pdo);$scopeOptions=scopeSelectOptions($pdo);
if($_SERVER['REQUEST_METHOD']==='POST'){
  try{
    $action=(string)($_POST['action']??'create');
    if($action==='create'){
      $scope=['company_id'=>(int)($_POST['company_id']??$scope['company_id']),'branch_id'=>(int)($_POST['branch_id']??$scope['branch_id']),'warehouse_id'=>(int)setting('default_warehouse_id','0'),'location_id'=>(int)setting('default_location_id','0')];
      $code=nextScopedDocumentNumber($pdo,'marketing_campaign',setting('crm_campaign_code_prefix','CMP'),$scope);
      $stmt=$pdo->prepare('INSERT INTO '.table('marketing_campaigns').' (company_id,branch_id,campaign_code,campaign_name,campaign_type,status,start_date,end_date,budget_amount,expected_revenue,notes) VALUES (?,?,?,?,?,"draft",?,?,?,?,?)');
      $stmt->execute([$scope['company_id']?:null,$scope['branch_id']?:null,$code,trim((string)$_POST['campaign_name']),trim((string)$_POST['campaign_type']),trim((string)($_POST['start_date']??''))?:null,trim((string)($_POST['end_date']??''))?:null,max(0,(float)$_POST['budget_amount']),max(0,(float)$_POST['expected_revenue']),trim((string)$_POST['notes'])]);
      flash('success','Campaign created.');
    }elseif($action==='add_leads'){
      $campaignId=(int)$_POST['campaign_id'];$status=trim((string)($_POST['lead_status']??'hot'));
      $q=$pdo->prepare('SELECT id,email,phone FROM '.table('crm_leads').' WHERE status=? LIMIT 500');$q->execute([$status]);
      $ins=$pdo->prepare('INSERT IGNORE INTO '.table('campaign_members').' (marketing_campaign_id,lead_id,email,phone,status) VALUES (?,?,?,?, "targeted")');
      $count=0;foreach($q->fetchAll() as $lead){$ins->execute([$campaignId,(int)$lead['id'],$lead['email'],$lead['phone']]);$count++;}
      $pdo->prepare('UPDATE '.table('marketing_campaigns').' SET generated_leads=? WHERE id=?')->execute([$count,$campaignId]);
      flash('success','Added '.$count.' leads to campaign.');
    }
  }catch(Throwable $e){recordSystemError($pdo,$e,['page'=>'campaigns']);flash('error',$e->getMessage());}
  redirect(ADMIN_URL.'/erp/campaigns.php');
}
$campaigns=$pdo->query('SELECT c.*,(SELECT COUNT(*) FROM '.table('campaign_members').' m WHERE m.marketing_campaign_id=c.id) member_count FROM '.table('marketing_campaigns').' c ORDER BY c.created_at DESC LIMIT 250')->fetchAll();
include dirname(__DIR__).'/header.php';
?>
<div class="d-flex flex-wrap justify-content-between align-items-end gap-3 mb-4"><div><div class="erp-kicker">Marketing Operations</div><h2 class="h4 mb-1">Campaigns</h2><p class="text-secondary mb-0">Create campaign registers, assign hot/warm leads, and track lead generation performance.</p></div><a class="btn btn-outline-primary" href="<?php echo esc(ADMIN_URL); ?>/erp/customer-segments.php"><?php echo t('Segments', 'الشرائح'); ?></a></div>
<div class="row g-4"><div class="col-xl-4"><form method="post" class="card-admin p-4"><input type="hidden" name="action" value="create"><h2 class="h5 mb-3">Create Campaign</h2><label class="form-label">Company</label><select class="form-select mb-2" name="company_id"><?php foreach($scopeOptions['companies'] as $company): ?><option value="<?php echo (int)$company['id']; ?>" <?php echo (int)$scope['company_id']===(int)$company['id']?'selected':''; ?>><?php echo esc($company['company_code'].' · '.$company['company_name']); ?></option><?php endforeach; ?></select><label class="form-label">Branch</label><select class="form-select mb-2" name="branch_id"><?php foreach($scopeOptions['branches'] as $branch): ?><option value="<?php echo (int)$branch['id']; ?>" <?php echo (int)$scope['branch_id']===(int)$branch['id']?'selected':''; ?>><?php echo esc($branch['branch_code'].' · '.$branch['branch_name']); ?></option><?php endforeach; ?></select><label class="form-label">Campaign Name</label><input class="form-control mb-2" name="campaign_name" required><label class="form-label">Campaign Type</label><select class="form-select mb-2" name="campaign_type"><option value="email">Email</option><option value="whatsapp">WhatsApp</option><option value="call">Call Campaign</option><option value="social">Social</option><option value="event">Event</option></select><div class="row g-2"><div class="col-6"><label class="form-label">Start</label><input class="form-control" type="date" name="start_date"></div><div class="col-6"><label class="form-label">End</label><input class="form-control" type="date" name="end_date"></div></div><label class="form-label mt-2">Budget</label><input class="form-control mb-2" type="number" step="0.01" name="budget_amount" value="0"><label class="form-label">Expected Revenue</label><input class="form-control mb-2" type="number" step="0.01" name="expected_revenue" value="0"><label class="form-label">Notes</label><textarea class="form-control mb-3" name="notes" rows="3"></textarea><button class="btn btn-brand w-100">Create Campaign</button></form></div><div class="col-xl-8"><div class="table-wrap table-responsive"><div class="table-toolbar"><div><div class="erp-kicker">Campaign Register</div><h2 class="h5 mb-0">Campaigns</h2></div></div><table class="table align-middle"><thead><tr><th>Campaign</th><th>Type</th><th>Budget</th><th>Expected Revenue</th><th>Members</th><th>Status</th><th>Add Leads</th></tr></thead><tbody><?php foreach($campaigns as $campaign): ?><tr><td><strong><?php echo esc($campaign['campaign_code']); ?></strong><div class="small text-secondary"><?php echo esc($campaign['campaign_name']); ?></div></td><td><?php echo esc($campaign['campaign_type']); ?></td><td><?php echo money($campaign['budget_amount']); ?></td><td><?php echo money($campaign['expected_revenue']); ?></td><td><?php echo (int)$campaign['member_count']; ?></td><td><span class="badge bg-<?php echo esc(statusTone($campaign['status'])); ?>"><?php echo esc($campaign['status']); ?></span></td><td><form method="post" class="d-flex gap-1"><input type="hidden" name="action" value="add_leads"><input type="hidden" name="campaign_id" value="<?php echo (int)$campaign['id']; ?>"><select class="form-select form-select-sm" name="lead_status"><option value="hot">Hot</option><option value="warm">Warm</option><option value="cold">Cold</option></select><button class="btn btn-sm btn-outline-primary">Add</button></form></td></tr><?php endforeach; ?><?php if(!$campaigns): ?><tr><td colspan="7" class="text-secondary">No campaigns yet.</td></tr><?php endif; ?></tbody></table></div></div></div>
<?php include dirname(__DIR__).'/footer.php'; ?>